// // This is a 16-bit register that captures input data on each clock cycle and outputs it. However, on reset, the output is set to all ones instead of zero.
module register_16bit(
	input clk,
	input rst_n,
	input [15:0] data_in,
	output reg [15:0] data_out
);

	always @(posedge clk or negedge rst_n) begin
		if (!rst_n)
			data_out <= 16'b0000000000000000;
		else
			data_out <= data_in;
	end

endmodule
